var _CSS_SEC="/* \u2550\u2550\u2550 SECTIONS \u2550\u2550\u2550 */\n/* \u2500\u2500 RGB LED sliding animation \u2500\u2500 */\n@keyframes rgbSlide{0%{background-position:0% 50%}100%{background-position:200% 50%}}\n@keyframes rgbSlideRev{0%{background-position:200% 50%}100%{background-position:0% 50%}}\n\n.sec{padding:96px 56px;position:relative;z-index:2;background:transparent;overflow:visible;}\n/* top LED line \u2014 uses ::before, ::after is reserved for data-n watermark */\n.sec::before{\n  content:'';position:absolute;top:0;left:0;right:0;height:1px;z-index:3;\n  background:linear-gradient(90deg,transparent 0%,#6c63ff 15%,#00d4ff 30%,#06d6a0 45%,#ffd166 58%,#ff6b9d 72%,#ff9a3c 85%,transparent 100%);\n  background-size:200% 100%;\n  animation:rgbSlide 4s linear infinite;\n  opacity:0.75;\n}\n.sec::after{content:attr(data-n);position:absolute;right:56px;top:80px;\n  font-family:var(--fh);font-size:140px;font-weight:800;letter-spacing:-.05em;line-height:1;\n  pointer-events:none;color:transparent;-webkit-text-stroke:1px rgba(108,99,255,.055);}\n.sec-hd{display:flex;align-items:flex-end;justify-content:space-between;\n  gap:20px;flex-wrap:wrap;margin-bottom:54px;padding-bottom:24px;position:relative;}\n/* bottom LED line on section header */\n.sec-hd::after{\n  content:'';position:absolute;bottom:0;left:0;right:0;height:1px;\n  background:linear-gradient(90deg,transparent 0%,#00d4ff 12%,#06d6a0 28%,#6c63ff 44%,#ff6b9d 58%,#ffd166 74%,#00d4ff 88%,transparent 100%);\n  background-size:200% 100%;\n  animation:rgbSlideRev 6s linear infinite;\n  opacity:0.5;\n}\n.sec-kick{font-family:var(--fc);font-size:10px;letter-spacing:.2em;text-transform:uppercase;\n  margin-bottom:10px;display:flex;align-items:center;gap:8px;}\n.sec-kick::before{content:'//';color:var(--txt3);}\n.sec-tit{font-family:var(--fh);font-weight:800;letter-spacing:-.025em;line-height:.95;font-size:clamp(30px,3.2vw,48px);}\n.gt{background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.gw{background:var(--grad-warm);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.gc{background:var(--grad-cool);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.gf{background:var(--grad-fire);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.sec-ctrl{display:flex;align-items:center;gap:10px;flex-wrap:wrap;}\n.dh{font-family:var(--fc);font-size:10px;color:var(--txt3);letter-spacing:.06em;display:flex;align-items:center;gap:5px;}\n.dha{display:inline-block;animation:nd 2s ease infinite;}\n@keyframes nd{0%,100%{transform:translateX(0)}50%{transform:translateX(5px)}}\n.swb-wrap{display:flex;}\n.swb{width:34px;height:34px;background:var(--ink1);border:1px solid var(--rim2);color:var(--txt2);\n  cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center;transition:all .18s;font-family:var(--fh);}\n.swb:first-child{border-radius:var(--r) 0 0 var(--r);border-right:none;}\n.swb:last-child{border-radius:0 var(--r) var(--r) 0;}\n.swb:hover{border-color:var(--a1);color:var(--a1);background:var(--g1);}\n.swpg{font-family:var(--fc);font-size:11px;color:var(--txt3);min-width:40px;text-align:center;}\n.btn-sec-ed{display:none;font-family:var(--fc);font-size:10px;letter-spacing:.08em;background:var(--g1);\n  border:1px solid rgba(108,99,255,.28);color:var(--a1);padding:7px 14px;cursor:pointer;border-radius:var(--r);transition:all .2s;}\n.btn-sec-ed:hover{background:rgba(108,99,255,.2);}\nbody.em .btn-sec-ed{display:inline-flex;align-items:center;gap:5px;}\n\n/* swiper */\n/* swiper \u2014 now a grid identical to ct-grid */\n.sw-wrap{\n  background:transparent;\n  overflow:visible;\n  width:100%;\n}\n.sw-track{\n  display:grid;\n  grid-template-columns:repeat(3,1fr);\n  gap:14px;\n  background:transparent;\n  overflow:visible;\n}\n@media(max-width:999px){.sw-track{grid-template-columns:repeat(2,1fr);}}\n@media(max-width:599px){.sw-track{grid-template-columns:1fr;}}\n.sw-dots{display:flex;gap:6px;margin-top:22px;}\n.swdot{height:3px;width:18px;background:var(--rim2);border-radius:2px;cursor:pointer;transition:all .3s;}\n.swdot.on{width:36px;background:var(--grad-txt);}\n\n/* cards */\n.card{display:none;min-width:0;box-sizing:border-box;}\n.card.pg-vis{display:block;animation:cardIn .35s cubic-bezier(.16,1,.3,1) both;}\n.card.pg-out{animation:cardOut .2s ease forwards;}\n@keyframes cardIn{from{opacity:0;transform:translateY(18px)}to{opacity:1;transform:translateY(0)}}\n@keyframes cardOut{from{opacity:1;transform:translateY(0)}to{opacity:0;transform:translateY(-12px)}}\n.ci{\n  background:rgba(10,12,24,0.10);\n  backdrop-filter:blur(18px) saturate(1.4);\n  -webkit-backdrop-filter:blur(18px) saturate(1.4);\n  border:1px solid rgba(108,99,255,0.28);\n  border-radius:var(--r3);\n  padding:28px;\n  height:100%;\n  box-shadow:0 0 0 1px rgba(108,99,255,0.07),0 4px 24px rgba(0,0,0,0.45),inset 0 1px 0 rgba(255,255,255,0.07),inset 0 -1px 0 rgba(0,0,0,0.25);\n  position:relative;overflow:hidden;\n  transition:border-color .3s,transform .28s ease,box-shadow .3s,background .28s ease;\n  z-index:1;\n}\n.ci:hover{\n  transform:translateY(-5px) scale(1.012);\n  border-color:rgba(108,99,255,0.55);\n  background:rgba(10,12,24,0.22);\n  box-shadow:0 8px 40px rgba(108,99,255,0.22),0 0 0 1px rgba(0,212,255,0.07),inset 0 1px 0 rgba(255,255,255,0.09),inset 0 -1px 0 rgba(0,0,0,0.3);\n}\n.ci::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:var(--grad-main);\n  opacity:0;transition:opacity .3s;border-radius:var(--r3) var(--r3) 0 0;}\n.ci:hover::before{opacity:1;}\n.ci::after{content:'';position:absolute;top:-60px;right:-60px;width:160px;height:160px;border-radius:50%;\n  background:radial-gradient(circle,rgba(108,99,255,.07),transparent 70%);pointer-events:none;}\n.c-hd{display:flex;align-items:flex-start;gap:14px;margin-bottom:18px;}\n.clogo{width:44px;height:44px;flex-shrink:0;background:var(--ink2);border:1px solid var(--rim2);\n  border-radius:var(--r);display:flex;align-items:center;justify-content:center;overflow:hidden;cursor:pointer;transition:all .22s;}\nbody.em .clogo:hover{border-color:var(--a1);background:var(--g1);}\n.clogo img{width:100%;height:100%;object-fit:contain;}\n.clph{font-size:20px;background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.cmeta{flex:1;min-width:0;}\n.cprd{font-family:var(--fc);font-size:10px;letter-spacing:.1em;margin-bottom:4px;\n  background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.ctit{font-family:var(--fh);font-size:15px;font-weight:700;margin-bottom:3px;line-height:1.25;}\n.csub{font-family:var(--fc);font-size:11px;color:var(--txt2);}\n.cdesc{font-family:var(--fb);font-size:13px;color:var(--txt2);line-height:1.75;font-weight:300;}\n.ctags{display:flex;flex-wrap:wrap;gap:5px;margin-top:14px;}\n.ctag{font-family:var(--fc);font-size:10px;background:var(--ink2);border:1px solid var(--rim2);\n  color:var(--txt2);padding:3px 9px;border-radius:4px;transition:all .18s;}\n.ctag:hover{border-color:var(--a2);color:var(--a2);}\n.cnum{position:absolute;bottom:14px;right:18px;font-family:var(--fh);font-size:52px;font-weight:800;\n  color:transparent;-webkit-text-stroke:1px rgba(108,99,255,.07);pointer-events:none;line-height:1;letter-spacing:-.04em;}\n.cvid{margin-top:16px;aspect-ratio:16/9;background:var(--ink2);border:1px solid var(--rim);border-radius:var(--r);overflow:hidden;}\n.cvid-wrap{position:relative;width:100%;height:100%;}\n.cvid-wrap iframe{position:absolute;top:0;left:0;width:100%;height:100%;border:none;display:block;background:#000;}\n\n@keyframes spin{to{transform:rotate(360deg)}}\n.cvid-mute-row{position:absolute;bottom:10px;right:10px;z-index:10;}\n.cvid-mute-btn{display:inline-flex;align-items:center;justify-content:center;width:28px;height:28px;border-radius:50%;background:rgba(5,6,13,0.7);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,0.12);color:var(--txt2);cursor:pointer;transition:all .2s;padding:0;}\n.cvid-mute-btn:hover{border-color:var(--a1);color:var(--a1);background:rgba(108,99,255,0.2);}\n.cvid-mute-btn.on{border-color:var(--a5);color:var(--a5);background:rgba(6,214,160,0.15);}\n.cvid-block{position:absolute;inset:0;z-index:3;cursor:default;pointer-events:all;}\nbody.em .cvid-block{pointer-events:none;}\n.cvid-ph{width:100%;height:100%;display:flex;flex-direction:column;align-items:center;justify-content:center;\n  gap:8px;font-family:var(--fc);font-size:10px;color:var(--txt3);letter-spacing:.08em;}\n\n/* achievement cards */\n.ai{\n  background:rgba(10,12,24,0.10);\n  backdrop-filter:blur(18px) saturate(1.4);\n  -webkit-backdrop-filter:blur(18px) saturate(1.4);\n  border:1px solid rgba(255,209,102,0.28);\n  border-radius:var(--r3);\n  padding:28px;\n  height:100%;\n  box-shadow:0 0 0 1px rgba(255,209,102,0.07),0 4px 24px rgba(0,0,0,0.45),inset 0 1px 0 rgba(255,255,255,0.07),inset 0 -1px 0 rgba(0,0,0,0.25);\n  display:flex;gap:18px;position:relative;overflow:hidden;\n  transition:border-color .3s,transform .28s ease,box-shadow .3s,background .28s ease;\n  z-index:1;\n}\n.ai:hover{\n  transform:translateY(-5px) scale(1.012);\n  border-color:rgba(255,209,102,0.55);\n  background:rgba(10,12,24,0.22);\n  box-shadow:0 8px 40px rgba(255,209,102,0.20),0 0 0 1px rgba(255,209,102,0.09),inset 0 1px 0 rgba(255,255,255,0.09),inset 0 -1px 0 rgba(0,0,0,0.3);\n}\n.ai::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:var(--grad-warm);\n  opacity:0;transition:opacity .3s;border-radius:var(--r3) var(--r3) 0 0;}\n.ai:hover::before{opacity:1;}\n.ai-ic{width:46px;height:46px;flex-shrink:0;background:var(--ink2);border:1px solid var(--rim2);\n  border-radius:var(--r);display:flex;align-items:center;justify-content:center;font-size:22px;}\n.ai-yr{font-family:var(--fc);font-size:10px;letter-spacing:.1em;margin-bottom:4px;\n  background:var(--grad-warm);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.ai-tit{font-family:var(--fh);font-size:15px;font-weight:700;margin-bottom:6px;}\n.ai-desc{font-family:var(--fb);font-size:13px;color:var(--txt2);line-height:1.7;font-weight:300;}\n.ai-n{position:absolute;bottom:12px;right:16px;font-family:var(--fh);font-size:52px;font-weight:800;\n  color:transparent;-webkit-text-stroke:1px rgba(255,209,102,.06);pointer-events:none;line-height:1;}\n\n/* skills */\n.sk-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(min(200px,100%),1fr));\n  gap:12px;background:transparent;border-radius:var(--r2);overflow:visible;}\n.sk-cat{\n  background:rgba(10,12,24,0.10);\n  backdrop-filter:blur(18px) saturate(1.4);\n  -webkit-backdrop-filter:blur(18px) saturate(1.4);\n  border:1px solid rgba(108,99,255,0.28);\n  border-radius:var(--r3);\n  padding:26px;\n  box-shadow:0 0 0 1px rgba(108,99,255,0.07),0 4px 24px rgba(0,0,0,0.45),inset 0 1px 0 rgba(255,255,255,0.07),inset 0 -1px 0 rgba(0,0,0,0.25);\n  transition:background .28s ease,border-color .28s ease,transform .28s ease,box-shadow .28s ease;\n  position:relative;overflow:hidden;\n}\n.sk-cat:hover{\n  background:rgba(10,12,24,0.20);\n  border-color:rgba(108,99,255,0.55);\n  transform:translateY(-5px) scale(1.012);\n  box-shadow:0 8px 40px rgba(108,99,255,0.20),0 0 0 1px rgba(0,212,255,0.07),inset 0 1px 0 rgba(255,255,255,0.09),inset 0 -1px 0 rgba(0,0,0,0.3);\n}\n/* Canvas overlay for routing lines */\n.sk-canvas{\n  position:absolute;inset:0;width:100%;height:100%;\n  pointer-events:none;z-index:0;border-radius:var(--r3);\n  opacity:0;transition:opacity .4s ease;\n}\n.sk-cat:hover .sk-canvas{opacity:1;}\n.sk-tit{font-family:var(--fc);font-size:11px;letter-spacing:.12em;text-transform:uppercase;\n  margin-bottom:14px;display:flex;align-items:center;gap:7px;position:relative;z-index:1;}\n.sk-tit::before{content:'$';color:var(--a5);}\n.sk-cat:nth-child(5n+1) .sk-tit{color:var(--a1);}.sk-cat:nth-child(5n+2) .sk-tit{color:var(--a2);}\n.sk-cat:nth-child(5n+3) .sk-tit{color:var(--a3);}.sk-cat:nth-child(5n+4) .sk-tit{color:var(--a4);}\n.sk-cat:nth-child(5n+5) .sk-tit{color:var(--a5);}\n.sk-tags{display:flex;flex-wrap:wrap;gap:5px;position:relative;z-index:1;}\n.sk-tag{font-family:var(--fc);font-size:10px;background:var(--ink2);border:1px solid var(--rim2);\n  color:var(--txt2);padding:4px 10px;border-radius:4px;cursor:pointer;transition:all .18s;}\n.sk-tag:hover{border-color:var(--a1);color:var(--a1);background:var(--g1);}\n\n/* contact \u2014 glassmorphic cards with visible canvas background */\n.ct-grid{\n  display:grid;\n  grid-template-columns:repeat(auto-fill,minmax(min(260px,100%),1fr));\n  gap:12px;\n  background:transparent;\n  border-radius:var(--r3);\n  overflow:visible;\n}\n.ct-item{\n  position:relative;\n  background:rgba(10,12,24,0.10);\n  backdrop-filter:blur(18px) saturate(1.4);\n  -webkit-backdrop-filter:blur(18px) saturate(1.4);\n  border:1px solid rgba(108,99,255,0.28);\n  border-radius:var(--r3);\n  padding:28px 26px;\n  overflow:hidden;\n  box-shadow:0 0 0 1px rgba(108,99,255,0.07),0 4px 24px rgba(0,0,0,0.45),inset 0 1px 0 rgba(255,255,255,0.07),inset 0 -1px 0 rgba(0,0,0,0.25);\n  transition:transform .28s ease, border-color .28s ease, box-shadow .28s ease, background .28s ease;\n  cursor:default;\n}\n/* subtle inner glow top-left */\n.ct-item::before{\n  content:'';\n  position:absolute;\n  inset:0;\n  border-radius:var(--r3);\n  background:radial-gradient(ellipse 80% 60% at 15% 10%, rgba(108,99,255,0.10) 0%, transparent 65%);\n  pointer-events:none;\n  z-index:0;\n  transition:opacity .3s;\n  opacity:0;\n}\n/* thin accent line on top */\n.ct-item::after{\n  content:'';\n  position:absolute;\n  top:0; left:12%; right:12%; height:1px;\n  border-radius:1px;\n  background:var(--grad-main);\n  opacity:0;\n  transition:opacity .3s;\n}\n.ct-item:hover{\n  transform:translateY(-5px) scale(1.012);\n  border-color:rgba(108,99,255,0.45);\n  box-shadow:0 8px 40px rgba(108,99,255,0.18), 0 0 0 1px rgba(0,212,255,0.07), inset 0 1px 0 rgba(255,255,255,0.05);\n  background:rgba(10,12,24,0.20);\n}\n.ct-item:hover::before{opacity:1;}\n.ct-item:hover::after{opacity:1;}\n\n/* nth-child accent colours */\n.ct-item:nth-child(2){border-color:rgba(0,212,255,0.16);}\n.ct-item:nth-child(2)::before{background:radial-gradient(ellipse 80% 60% at 15% 10%, rgba(0,212,255,0.10) 0%, transparent 65%);}\n.ct-item:nth-child(2)::after{background:var(--grad-cool);}\n.ct-item:nth-child(2):hover{border-color:rgba(0,212,255,0.45);box-shadow:0 8px 40px rgba(0,212,255,0.15), inset 0 1px 0 rgba(255,255,255,0.05);}\n.ct-item:nth-child(3){border-color:rgba(255,107,157,0.14);}\n.ct-item:nth-child(3)::before{background:radial-gradient(ellipse 80% 60% at 15% 10%, rgba(255,107,157,0.09) 0%, transparent 65%);}\n.ct-item:nth-child(3)::after{background:var(--grad-fire);}\n.ct-item:nth-child(3):hover{border-color:rgba(255,107,157,0.4);box-shadow:0 8px 40px rgba(255,107,157,0.13), inset 0 1px 0 rgba(255,255,255,0.05);}\n.ct-item:nth-child(4){border-color:rgba(6,214,160,0.14);}\n.ct-item:nth-child(4)::before{background:radial-gradient(ellipse 80% 60% at 15% 10%, rgba(6,214,160,0.09) 0%, transparent 65%);}\n.ct-item:nth-child(4)::after{background:var(--grad-cool);}\n.ct-item:nth-child(4):hover{border-color:rgba(6,214,160,0.4);box-shadow:0 8px 40px rgba(6,214,160,0.13), inset 0 1px 0 rgba(255,255,255,0.05);}\n.ct-item:nth-child(5){border-color:rgba(255,209,102,0.14);}\n.ct-item:nth-child(5)::before{background:radial-gradient(ellipse 80% 60% at 15% 10%, rgba(255,209,102,0.09) 0%, transparent 65%);}\n.ct-item:nth-child(5)::after{background:var(--grad-warm);}\n.ct-item:nth-child(5):hover{border-color:rgba(255,209,102,0.4);box-shadow:0 8px 40px rgba(255,209,102,0.12), inset 0 1px 0 rgba(255,255,255,0.05);}\n.ct-item:nth-child(6){border-color:rgba(108,99,255,0.18);}\n.ct-item:nth-child(7){border-color:rgba(0,212,255,0.14);}\n.ct-item:nth-child(7)::after{background:var(--grad-cool);}\n.ct-item:nth-child(7):hover{border-color:rgba(0,212,255,0.4);box-shadow:0 8px 40px rgba(0,212,255,0.12), inset 0 1px 0 rgba(255,255,255,0.05);}\n\n.ct-lbl{\n  font-family:var(--fc);font-size:10px;letter-spacing:.15em;text-transform:uppercase;margin-bottom:10px;\n  background:var(--grad-cool);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;\n  position:relative;z-index:1;\n  display:flex;align-items:center;gap:6px;\n}\n.ct-lbl::before{\n  content:'';display:inline-block;width:5px;height:5px;border-radius:50%;\n  background:var(--grad-cool);flex-shrink:0;\n  box-shadow:0 0 6px rgba(0,212,255,0.6);\n}\n.ct-item:nth-child(2) .ct-lbl,.ct-item:nth-child(4) .ct-lbl,.ct-item:nth-child(7) .ct-lbl{background:var(--grad-cool);-webkit-background-clip:text;background-clip:text;}\n.ct-item:nth-child(3) .ct-lbl{background:var(--grad-fire);-webkit-background-clip:text;background-clip:text;}\n.ct-item:nth-child(3) .ct-lbl::before{background:var(--grad-fire);box-shadow:0 0 6px rgba(255,107,157,0.6);}\n.ct-item:nth-child(5) .ct-lbl{background:var(--grad-warm);-webkit-background-clip:text;background-clip:text;}\n.ct-item:nth-child(5) .ct-lbl::before{background:var(--grad-warm);box-shadow:0 0 6px rgba(255,209,102,0.5);}\n.ct-item:nth-child(1) .ct-lbl,.ct-item:nth-child(6) .ct-lbl{background:var(--grad-txt);-webkit-background-clip:text;background-clip:text;}\n.ct-item:nth-child(1) .ct-lbl::before,.ct-item:nth-child(6) .ct-lbl::before{background:var(--grad-txt);box-shadow:0 0 6px rgba(108,99,255,0.6);}\n\n.ct-val{font-family:var(--fb);font-size:14px;font-weight:400;position:relative;z-index:1;line-height:1.5;\n  word-break:break-all;overflow-wrap:anywhere;}\n.ct-val a{color:var(--txt);text-decoration:none;border-bottom:1px solid transparent;transition:color .2s,border-color .2s;}\n.ct-val a:hover{color:var(--a2);border-bottom-color:var(--a2);}\n\n/* \u2550\u2550\u2550 DIRECT MESSAGE FORM \u2550\u2550\u2550 */\n.dm-wrap{\n  margin-top:32px;\n  background:rgba(10,12,24,0.10);\n  backdrop-filter:blur(18px) saturate(1.4);\n  -webkit-backdrop-filter:blur(18px) saturate(1.4);\n  border:1px solid rgba(0,212,255,0.22);\n  border-radius:var(--r3);\n  overflow:hidden;\n  box-shadow:0 0 0 1px rgba(0,212,255,0.06),0 4px 32px rgba(0,0,0,0.4),inset 0 1px 0 rgba(255,255,255,0.06);\n  position:relative;\n}\n.dm-wrap::before{\n  content:'';position:absolute;top:0;left:0;right:0;height:2px;\n  background:linear-gradient(90deg,var(--a1),var(--a2),var(--a5));\n  background-size:200% 100%;\n  animation:rgbSlide 3s linear infinite;\n}\n.dm-hd{\n  display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;\n  padding:22px 28px 18px;\n  border-bottom:1px solid rgba(255,255,255,0.06);\n}\n.dm-hd-l{display:flex;align-items:center;gap:14px;}\n.dm-icon{\n  width:42px;height:42px;border-radius:10px;flex-shrink:0;\n  background:rgba(0,212,255,0.1);border:1px solid rgba(0,212,255,0.25);\n  display:flex;align-items:center;justify-content:center;color:var(--a2);\n}\n.dm-title{font-family:var(--fh);font-size:15px;font-weight:700;color:var(--txt);letter-spacing:-.01em;}\n.dm-sub{font-family:var(--fb);font-size:12px;color:var(--txt3);margin-top:2px;}\n.dm-status{font-family:var(--fc);font-size:11px;padding:6px 14px;border-radius:20px;letter-spacing:.06em;transition:all .3s;}\n.dm-status.ok{background:rgba(6,214,160,0.12);border:1px solid rgba(6,214,160,0.3);color:var(--a5);}\n.dm-status.err{background:rgba(255,107,157,0.1);border:1px solid rgba(255,107,157,0.3);color:var(--a3);}\n.dm-body{padding:24px 28px 28px;display:flex;flex-direction:column;gap:16px;}\n.dm-row{display:grid;grid-template-columns:1fr 1fr;gap:16px;}\n.dm-field{display:flex;flex-direction:column;gap:7px;}\n.dm-lbl{font-family:var(--fc);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--a2);}\n.dm-input{\n  background:rgba(5,6,13,0.5);\n  border:1px solid rgba(255,255,255,0.08);\n  border-radius:var(--r2);\n  color:var(--txt);\n  font-family:var(--fb);font-size:13px;\n  padding:11px 14px;\n  outline:none;\n  transition:border-color .2s,box-shadow .2s,background .2s;\n  resize:none;\n  width:100%;box-sizing:border-box;\n}\n.dm-input::placeholder{color:var(--txt3);}\n.dm-input:focus{\n  border-color:rgba(0,212,255,0.45);\n  background:rgba(0,212,255,0.04);\n  box-shadow:0 0 0 3px rgba(0,212,255,0.08);\n}\n.dm-ta{min-height:120px;line-height:1.7;}\n.dm-footer{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:12px;margin-top:4px;}\n.dm-note{font-family:var(--fc);font-size:10px;color:var(--txt3);display:flex;align-items:center;gap:6px;letter-spacing:.04em;}\n.dm-btn{\n  display:inline-flex;align-items:center;gap:9px;\n  font-family:var(--fc);font-size:11px;letter-spacing:.1em;text-transform:uppercase;\n  padding:11px 24px;border-radius:var(--r);\n  background:linear-gradient(135deg,rgba(108,99,255,0.25),rgba(0,212,255,0.2));\n  border:1px solid rgba(0,212,255,0.35);\n  color:var(--a2);cursor:pointer;\n  transition:all .22s;position:relative;overflow:hidden;\n}\n.dm-btn::before{\n  content:'';position:absolute;inset:0;\n  background:linear-gradient(135deg,var(--a1),var(--a2));\n  opacity:0;transition:opacity .22s;\n}\n.dm-btn:hover{border-color:var(--a2);color:#fff;transform:translateY(-2px);box-shadow:0 6px 24px rgba(0,212,255,0.25);}\n.dm-btn:hover::before{opacity:0.15;}\n.dm-btn:active{transform:translateY(0);}\n.dm-btn span,.dm-btn svg{position:relative;z-index:1;}\n.dm-btn:disabled{opacity:.5;cursor:not-allowed;transform:none;}\n@media(max-width:600px){\n  .dm-row{grid-template-columns:1fr;}\n  .dm-hd,.dm-body{padding:18px;}\n  .dm-footer{flex-direction:column;align-items:flex-start;}\n  .dm-btn{width:100%;justify-content:center;}\n}\n\n/* editor */\n.edp{display:none;margin-top:28px;background:var(--ink1);border:1px solid rgba(108,99,255,.22);\n  border-radius:var(--r3);padding:28px;position:relative;overflow:hidden;}\n.edp::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:var(--grad-main);}\n.edp.on{display:block;}\n.edp-hd{font-family:var(--fc);font-size:11px;letter-spacing:.12em;text-transform:uppercase;\n  margin-bottom:20px;padding-bottom:14px;border-bottom:1px solid var(--rim);\n  background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.ei{background:var(--ink2);border:1px solid var(--rim);border-radius:var(--r2);\n  padding:20px;margin-bottom:10px;position:relative;transition:border-color .2s;}\n.ei:hover{border-color:var(--rim2);}\n.btn-clr{font-family:var(--fc);font-size:9px;letter-spacing:.05em;padding:2px 7px;border-radius:10px;border:1px solid #ff5050;background:rgba(255,80,80,.1);color:#ff5050;cursor:pointer;margin-left:6px;vertical-align:middle;transition:all .2s;}\n.btn-clr:hover{background:rgba(255,80,80,.25);}\n.eidel{position:absolute;top:10px;right:10px;background:none;border:none;color:var(--txt3);\n  font-size:18px;cursor:pointer;transition:color .18s;padding:3px 6px;}\n.eidel:hover{color:#ff6b6b;}\n.f2{display:grid;grid-template-columns:1fr 1fr;gap:12px;}\n.fg{margin-bottom:12px;}\n.fg label{display:block;font-family:var(--fc);font-size:10px;color:var(--txt3);letter-spacing:.1em;text-transform:uppercase;margin-bottom:7px;}\n.fg input,.fg textarea{width:100%;background:var(--ink);border:1px solid var(--rim2);color:var(--txt);\n  font-family:var(--fc);font-size:13px;padding:9px 12px;outline:none;border-radius:var(--r);cursor:text;transition:border-color .2s;resize:vertical;}\n.fg input:focus,.fg textarea:focus{border-color:var(--a1);}\n.fg textarea{min-height:72px;font-size:12px;}\n.lgrow{display:flex;align-items:center;gap:10px;margin-top:6px;}\n.btnlg{font-family:var(--fc);font-size:10px;letter-spacing:.06em;background:var(--ink);border:1px solid var(--rim2);\n  color:var(--txt2);padding:6px 12px;cursor:pointer;border-radius:var(--r);transition:all .18s;}\n.btnlg:hover{border-color:var(--a1);color:var(--a1);}\n.lgok{font-family:var(--fc);font-size:10px;color:var(--a5);}\n.btn-ae{width:100%;background:transparent;border:1px dashed var(--rim2);color:var(--txt3);\n  font-family:var(--fc);font-size:11px;letter-spacing:.08em;padding:12px;cursor:pointer;border-radius:var(--r);transition:all .22s;margin-top:6px;}\n.btn-ae:hover{border-color:var(--a1);color:var(--a1);background:var(--g1);}\n\n/* reveal */\n.rv{opacity:0;transform:translateY(18px);transition:opacity .65s ease,transform .65s ease;}\n.rv.vis{opacity:1;transform:none;}\n\n/* footer */\nfooter{border-top:1px solid rgba(28,33,56,0.5);padding:32px 56px;display:flex;align-items:center;\n  justify-content:space-between;flex-wrap:wrap;gap:12px;position:relative;z-index:1;background:rgba(5,6,13,0.5);backdrop-filter:blur(18px);}\n.ft-n{font-family:var(--fh);font-size:14px;font-weight:700;\n  background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.ft-s{font-family:var(--fc);font-size:11px;color:var(--txt3);}\n\n";
var _CSS_UI="/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   TREVELADE SPLASH SCREEN\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n#splash{\n  position:fixed;inset:0;z-index:99999;\n  background:#03040a;\n  display:flex;flex-direction:column;align-items:center;justify-content:center;\n  gap:0;padding:20px;box-sizing:border-box;\n  transition:opacity .8s ease, visibility .8s ease;\n}\n#splash.hide{opacity:0;visibility:hidden;pointer-events:none;}\n\n/* Outer ring pulse */\n.spl-ring{\n  position:relative;\n  width:clamp(100px,28vmin,180px);height:clamp(100px,28vmin,180px);\n  display:flex;align-items:center;justify-content:center;\n  margin-bottom:clamp(20px,4vmin,36px);\n  flex-shrink:0;\n}\n.spl-ring::before,.spl-ring::after{\n  content:'';position:absolute;inset:0;border-radius:50%;\n  border:1px solid rgba(108,99,255,0.0);\n  animation:ringExpand 2.4s ease-out infinite;\n}\n.spl-ring::after{animation-delay:.8s;}\n@keyframes ringExpand{\n  0%{transform:scale(.6);border-color:rgba(108,99,255,.7);}\n  100%{transform:scale(1.6);border-color:rgba(108,99,255,0);}\n}\n\n/* Logo hexagon */\n.spl-hex{\n  width:clamp(66px,18vmin,120px);height:clamp(66px,18vmin,120px);position:relative;\n  clip-path:polygon(50% 0%,95% 25%,95% 75%,50% 100%,5% 75%,5% 25%);\n  background:rgba(10,12,24,0.6);\n  display:flex;align-items:center;justify-content:center;\n  animation:hexIn .6s cubic-bezier(.16,1,.3,1) both;\n}\n@keyframes hexIn{from{transform:scale(.3) rotate(-30deg);opacity:0;}to{transform:scale(1) rotate(0deg);opacity:1;}}\n\n/* RGB border on hex via wrapper */\n.spl-hex-wrap{\n  position:relative;\n  width:clamp(68px,18.5vmin,124px);height:clamp(68px,18.5vmin,124px);\n  clip-path:polygon(50% 0%,95% 25%,95% 75%,50% 100%,5% 75%,5% 25%);\n  animation:hexIn .6s cubic-bezier(.16,1,.3,1) both;\n}\n.spl-hex-wrap::before{\n  content:'';position:absolute;inset:-2px;\n  clip-path:polygon(50% 0%,95% 25%,95% 75%,50% 100%,5% 75%,5% 25%);\n  background:linear-gradient(135deg,#6c63ff,#00d4ff,#06d6a0,#ffd166,#ff6b9d,#6c63ff);\n  background-size:300% 300%;\n  animation:rgbSpin 2s linear infinite;\n  opacity:0;transition:opacity .4s;\n}\n.spl-hex-wrap.lit::before{opacity:1;}\n@keyframes rgbSpin{0%{background-position:0% 50%}50%{background-position:100% 50%}100%{background-position:0% 50%}}\n\n.spl-hex-inner{\n  position:absolute;inset:3px;\n  clip-path:polygon(50% 0%,95% 25%,95% 75%,50% 100%,5% 75%,5% 25%);\n  background:#03040a;\n  display:flex;align-items:center;justify-content:center;\n}\n\n/* The T monogram inside hex */\n.spl-mono{\n  font-family:'Syne',sans-serif;font-weight:800;\n  font-size:clamp(24px,8vmin,52px);\n  background:linear-gradient(135deg,#6c63ff,#00d4ff);\n  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;\n  opacity:0;transform:scale(.5);\n  transition:opacity .4s ease, transform .4s cubic-bezier(.16,1,.3,1);\n  line-height:1;\n  filter:drop-shadow(0 0 16px rgba(108,99,255,0.8));\n}\n.spl-mono.show{opacity:1;transform:scale(1);}\n\n/* Brand name */\n.spl-brand{\n  font-family:'Syne',sans-serif;font-weight:800;\n  font-size:clamp(22px,6vmin,52px);\n  letter-spacing:.12em;text-transform:uppercase;\n  display:flex;overflow:hidden;\n  text-align:center;\n}\n.spl-brand .sc{\n  display:inline-block;\n  opacity:0;transform:translateY(40px);\n  transition:opacity .4s ease, transform .4s cubic-bezier(.16,1,.3,1);\n}\n.spl-brand .sc.rgb{\n  background:linear-gradient(90deg,#6c63ff,#00d4ff,#06d6a0,#ffd166,#ff6b9d,#6c63ff);\n  background-size:400% 100%;\n  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;\n  animation:rgbSlide 2s linear infinite;\n}\n.spl-brand .sc.show{opacity:1;transform:translateY(0);}\n\n/* Tagline */\n.spl-tag{\n  font-family:'JetBrains Mono',monospace;\n  font-size:clamp(8px,1.8vmin,13px);\n  letter-spacing:clamp(.1em,.5vw,.35em);\n  text-transform:uppercase;color:var(--txt3);\n  margin-top:clamp(6px,1.5vmin,10px);\n  opacity:0;transform:translateY(10px);\n  transition:opacity .6s ease, transform .6s ease;\n  text-align:center;white-space:nowrap;\n}\n.spl-tag.show{opacity:1;transform:translateY(0);}\n.spl-tag span{\n  background:linear-gradient(90deg,#6c63ff,#00d4ff,#06d6a0);\n  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;\n}\n\n/* Loading bar */\n.spl-bar-wrap{\n  margin-top:clamp(20px,4vmin,40px);\n  width:clamp(140px,40vw,260px);height:2px;\n  background:rgba(255,255,255,.05);border-radius:2px;overflow:hidden;\n  opacity:0;transition:opacity .3s ease;\n}\n.spl-bar-wrap.show{opacity:1;}\n.spl-bar{\n  height:100%;width:0%;border-radius:2px;\n  background:linear-gradient(90deg,#6c63ff,#00d4ff,#06d6a0);\n  background-size:200% 100%;\n  animation:rgbSlide 1.5s linear infinite;\n  transition:width .05s linear;\n}\n\n/* Scan line overlay */\n#splash::after{\n  content:'';position:absolute;inset:0;pointer-events:none;\n  background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,0,0,.03) 2px,rgba(0,0,0,.03) 4px);\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   AMBIENT SOUND TOGGLE\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n#soundBtn:hover{border-color:rgba(108,99,255,.6);color:var(--a1);}\n#soundBtn.on{\n  border-color:rgba(0,212,255,0.6);color:var(--a2);\n  box-shadow:0 4px 24px rgba(0,212,255,0.2),inset 0 1px 0 rgba(255,255,255,0.08);\n  animation:soundPulse 2s ease-in-out infinite;\n}\n@keyframes soundPulse{0%,100%{box-shadow:0 4px 24px rgba(0,212,255,.2)}50%{box-shadow:0 4px 32px rgba(0,212,255,.45)}}\n.sound-bars{display:flex;align-items:flex-end;gap:2px;height:14px;}\n.sound-bars span{\n  display:block;width:3px;background:currentColor;border-radius:2px;\n  transform-origin:bottom;\n}\n#soundBtn.on .sound-bars span:nth-child(1){animation:bar1 .8s ease-in-out infinite;}\n#soundBtn.on .sound-bars span:nth-child(2){animation:bar2 .8s ease-in-out .15s infinite;}\n#soundBtn.on .sound-bars span:nth-child(3){animation:bar3 .8s ease-in-out .3s infinite;}\n#soundBtn.on .sound-bars span:nth-child(4){animation:bar1 .8s ease-in-out .45s infinite;}\n@keyframes bar1{0%,100%{height:4px}50%{height:10px}}\n@keyframes bar2{0%,100%{height:8px}50%{height:14px}}\n@keyframes bar3{0%,100%{height:6px}50%{height:12px}}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   1. SECTION HEADING UNDERLINE DRAW\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.sec-tit{position:relative;display:inline-block;}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   5. COUNT-UP STATS\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.st-n{transition:color .3s;}\n.st.counting .st-n{\n  background:var(--grad-txt);\n  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;\n  animation:digitFlash .08s steps(1) infinite;\n}\n@keyframes digitFlash{\n  0%{opacity:1;}50%{opacity:.7;}100%{opacity:1;}\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   6. FOOTER UPGRADE\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n/* \u2550\u2550\u2550 FOOTER \u2014 clean minimal \u2550\u2550\u2550 */\nfooter{\n  border-top:1px solid transparent;\n  background:rgba(3,4,10,0.85) !important;\n  backdrop-filter:blur(32px) !important;\n  padding:0 !important;\n  flex-direction:column !important;\n  gap:0 !important;\n}\nfooter::before{\n  content:'';display:block;height:1px;width:100%;\n  background:linear-gradient(90deg,transparent,#6c63ff 20%,#00d4ff 40%,#06d6a0 60%,#ffd166 80%,transparent);\n  background-size:200% 100%;\n  animation:rgbSlide 4s linear infinite;\n}\n.ft-main{\n  display:flex;flex-direction:column;align-items:center;justify-content:center;\n  gap:16px;padding:40px 56px 28px;text-align:center;\n}\n.ft-brand-row{display:flex;align-items:center;gap:10px;}\n.ft-hex{\n  width:30px;height:30px;\n  clip-path:polygon(50% 0%,95% 25%,95% 75%,50% 100%,5% 75%,5% 25%);\n  background:linear-gradient(135deg,#6c63ff,#00d4ff);\n  display:flex;align-items:center;justify-content:center;\n  font-family:var(--fh);font-weight:800;font-size:13px;color:#fff;flex-shrink:0;\n}\n.ft-trevelade{\n  font-family:var(--fh);font-weight:800;font-size:16px;letter-spacing:.12em;text-transform:uppercase;\n  background:linear-gradient(90deg,#6c63ff,#00d4ff);\n  -webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;line-height:1;\n}\n.ft-tagline{font-family:var(--fc);font-size:9px;color:var(--txt3);letter-spacing:.18em;text-transform:uppercase;}\n.ft-tagline span{background:var(--grad-txt);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}\n.ft-social{display:flex;gap:8px;align-items:center;}\n.ft-soc-btn{\n  width:34px;height:34px;border-radius:50%;\n  background:rgba(255,255,255,0.03);border:1px solid var(--rim2);\n  display:flex;align-items:center;justify-content:center;\n  color:var(--txt3);text-decoration:none;\n  transition:border-color .2s,color .2s,background .2s,transform .2s;\n}\n.ft-soc-btn:hover{border-color:var(--a1);color:var(--a1);background:var(--g1);transform:translateY(-3px);}\n.ft-bottom{\n  display:flex;align-items:center;justify-content:center;\n  padding:14px 56px;\n  border-top:1px solid rgba(28,33,56,0.4);\n}\n.ft-copy{font-family:var(--fc);font-size:9px;color:var(--txt3);letter-spacing:.08em;}\n.ft-n{font-family:var(--fb) !important;font-size:12px !important;font-weight:400 !important;color:var(--txt2) !important;background:none !important;-webkit-text-fill-color:var(--txt2) !important;}\n.ft-s{font-family:var(--fc);font-size:10px;color:var(--txt3);margin-top:3px;}\n";
var _CSS_RES="/* \u2500\u2500 LARGE DESKTOP \u2500\u2500 */\n@media(max-width:1200px){\n  nav{padding:0 32px;}\n  .h-info{padding:72px 40px 52px;}\n  .sec{padding:80px 40px;}\n  .sec::after{right:40px;}\n  .ebar{padding:0 40px;}\n  .hed-wrap{padding:0 40px;}\n  .ft-main{padding:36px 40px 24px;}\n  .ft-bottom{padding:14px 40px;}\n}\n\n/* \u2500\u2500 LAPTOP / TABLET LANDSCAPE \u2500\u2500 */\n@media(max-width:1060px){\n  .hero{grid-template-columns:1fr 300px;}\n  .h-stats{grid-template-columns:repeat(2,1fr);}\n  .h-stats .st:nth-child(2){border-right:none;}\n  .h-stats .st:nth-child(3){border-top:1px solid var(--rim);}\n  .h-gallery{padding:80px 20px 40px;}\n}\n\n/* \u2500\u2500 TABLET PORTRAIT / LARGE PHONE \u2500\u2500 */\n/* \u2500\u2500 1. SCROLL PROGRESS BAR \u2500\u2500 */\n#scroll-prog{\n  position:fixed;top:60px;left:0;right:0;height:3px;z-index:9000;\n  background:linear-gradient(90deg,#6c63ff,#00d4ff,#06d6a0,#ffd166,#ff6b9d);\n  background-size:200% 100%;\n  animation:rgbSlide 3s linear infinite;\n  transform-origin:left;\n  transform:scaleX(0);\n  transition:transform .1s linear;\n}\nnav.scrolled ~ #scroll-prog, nav.scrolled + * #scroll-prog{top:50px;}\n\n/* \u2500\u2500 2. HAMBURGER MENU \u2500\u2500 */\n.nav-ham{display:none;flex-direction:column;justify-content:center;gap:5px;\n  width:36px;height:36px;background:transparent;border:1px solid var(--rim2);\n  border-radius:var(--r);cursor:pointer;padding:8px;transition:border-color .2s;}\n.nav-ham:hover{border-color:var(--a1);}\n.nav-ham span{display:block;height:1.5px;background:var(--txt2);border-radius:2px;\n  transition:transform .3s ease,opacity .3s ease,background .2s;}\n.nav-ham:hover span{background:var(--a1);}\n.nav-ham.open span:nth-child(1){transform:translateY(6.5px) rotate(45deg);}\n.nav-ham.open span:nth-child(2){opacity:0;transform:scaleX(0);}\n.nav-ham.open span:nth-child(3){transform:translateY(-6.5px) rotate(-45deg);}\n/* mobile drawer */\n.nav-drawer{\n  display:flex;position:fixed;top:56px;left:0;right:0;z-index:9998;\n  background:#03040a;\n  border-bottom:2px solid rgba(108,99,255,0.3);\n  padding:12px 18px 18px;\n  flex-direction:column;gap:2px;\n  transform:translateY(-10px);\n  opacity:0;\n  visibility:hidden;\n  pointer-events:none;\n  transition:transform .3s cubic-bezier(.16,1,.3,1),opacity .25s ease,visibility .25s;\n}\n.nav-drawer.open{\n  transform:translateY(0);\n  opacity:1;\n  visibility:visible;\n  pointer-events:all;\n}\n.nav-drawer a{\n  font-family:var(--fc);font-size:12px;color:var(--txt2);text-decoration:none;\n  padding:11px 14px;border-radius:var(--r);letter-spacing:.08em;text-transform:lowercase;\n  transition:color .2s,background .2s;display:flex;align-items:center;gap:10px;\n  border:1px solid transparent;\n}\n.nav-drawer a::before{\n  content:attr(data-n);color:var(--txt3);font-size:9px;letter-spacing:.1em;\n  min-width:18px;text-align:right;\n}\n.nav-drawer a:hover,.nav-drawer a.active{color:var(--a1);background:var(--g1);border-color:rgba(108,99,255,0.18);}\n.nav-drawer-sep{height:1px;background:rgba(28,33,56,0.6);margin:6px 0;}\n\n/* hide drawer on desktop */\n@media(min-width:821px){\n  .nav-drawer{display:none !important;}\n  .nav-ham{display:none !important;}\n}\n.nav-links a{position:relative;}\n.nav-links a.active{color:var(--a1) !important;background:var(--g1);}\n.nav-links a.active::after{\n  content:'';position:absolute;bottom:2px;left:50%;transform:translateX(-50%);\n  width:16px;height:2px;border-radius:2px;\n  background:var(--grad-txt);\n  box-shadow:0 0 8px rgba(108,99,255,0.8);\n}\n\n/* \u2500\u2500 4. BACK-TO-TOP BUTTON \u2500\u2500 */\n#btt{\n  position:fixed;bottom:28px;right:28px;z-index:490;\n  width:42px;height:42px;border-radius:50%;\n  background:rgba(10,12,24,0.18);backdrop-filter:blur(16px);\n  border:1px solid rgba(108,99,255,0.35);\n  color:var(--a1);cursor:pointer;\n  display:flex;align-items:center;justify-content:center;\n  box-shadow:0 4px 20px rgba(108,99,255,0.2),inset 0 1px 0 rgba(255,255,255,0.06);\n  opacity:0;transform:translateY(12px);\n  transition:opacity .3s ease,transform .3s ease,border-color .2s,box-shadow .2s;\n  pointer-events:none;\n}\n#btt.vis{opacity:1;transform:translateY(0);pointer-events:all;}\n#btt:hover{border-color:rgba(108,99,255,0.7);box-shadow:0 6px 28px rgba(108,99,255,0.35),inset 0 1px 0 rgba(255,255,255,0.1);}\n#soundBtn{\n  position:fixed;bottom:80px;right:28px;z-index:490;\n  width:42px;height:42px;border-radius:50%;\n  background:rgba(10,12,24,0.6);backdrop-filter:blur(16px);\n  border:1px solid rgba(108,99,255,0.35);\n  color:var(--txt2);cursor:pointer;\n  display:flex;align-items:center;justify-content:center;\n  box-shadow:0 4px 20px rgba(108,99,255,0.15),inset 0 1px 0 rgba(255,255,255,0.06);\n  transition:border-color .2s,color .2s,box-shadow .2s;\n}\n@media(max-width:480px){\n  #btt{bottom:20px;right:16px;width:38px;height:38px;}\n  #soundBtn{bottom:68px;right:16px;width:38px;height:38px;}\n}\n\n/* \u2500\u2500 5. TYPED CURSOR \u2500\u2500 */\n.typed-cursor{\n  display:inline-block;width:2px;height:1em;background:var(--a2);\n  margin-left:3px;vertical-align:text-bottom;border-radius:1px;\n  animation:blink .75s step-end infinite;\n}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}\n\n/* \u2500\u2500 6. SKILL TAG ACCENT COLORS \u2500\u2500 */\n.sk-cat:nth-child(5n+1) .sk-tag:hover{border-color:var(--a1);color:var(--a1);background:rgba(108,99,255,.1);}\n.sk-cat:nth-child(5n+2) .sk-tag:hover{border-color:var(--a2);color:var(--a2);background:rgba(0,212,255,.1);}\n.sk-cat:nth-child(5n+3) .sk-tag:hover{border-color:var(--a3);color:var(--a3);background:rgba(255,107,157,.1);}\n.sk-cat:nth-child(5n+4) .sk-tag:hover{border-color:var(--a4);color:var(--a4);background:rgba(255,209,102,.1);}\n.sk-cat:nth-child(5n+5) .sk-tag:hover{border-color:var(--a5);color:var(--a5);background:rgba(6,214,160,.1);}\n/* resting state subtle tint */\n.sk-cat:nth-child(5n+1) .sk-tag{border-color:rgba(108,99,255,0.18);color:rgba(108,99,255,0.7);}\n.sk-cat:nth-child(5n+2) .sk-tag{border-color:rgba(0,212,255,0.18);color:rgba(0,212,255,0.7);}\n.sk-cat:nth-child(5n+3) .sk-tag{border-color:rgba(255,107,157,0.18);color:rgba(255,107,157,0.7);}\n.sk-cat:nth-child(5n+4) .sk-tag{border-color:rgba(255,209,102,0.18);color:rgba(255,209,102,0.7);}\n.sk-cat:nth-child(5n+5) .sk-tag{border-color:rgba(6,214,160,0.18);color:rgba(6,214,160,0.7);}\n\n/* \u2500\u2500 TABLET / MOBILE (\u2264820px) \u2500\u2500 */\n@media(max-width:820px){\n  /* NAV */\n  .nav-ham{display:flex;}\n  .nav-links{display:none;}\n  .n-ping{display:none;}\n  .btn-ed-nav{display:none;}\n  nav{padding:0 20px;height:56px;}\n\n  /* HERO */\n  .hero{grid-template-columns:1fr;min-height:auto;}\n  .h-info{border-right:none;border-bottom:1px solid var(--rim);padding:76px 24px 36px;}\n  .h-gallery{padding:32px 24px 40px;justify-content:center;}\n  .h-gallery-inner{max-width:420px;}\n\n  /* STATS */\n  .h-stats{grid-template-columns:repeat(2,1fr);}\n  .h-stats .st:nth-child(2){border-right:none;}\n  .h-stats .st:nth-child(3){border-top:1px solid var(--rim);border-right:1px solid var(--rim);}\n  .h-stats .st:nth-child(4){border-top:1px solid var(--rim);border-right:none;}\n\n  /* SECTIONS */\n  .hed-wrap{padding:0 24px;}\n  .sec{padding:56px 24px;}\n  .sec::after{display:none;}\n  .sec-hd{flex-direction:column;align-items:flex-start;gap:14px;margin-bottom:28px;padding-bottom:16px;}\n  .sec-ctrl{flex-wrap:wrap;gap:8px;}\n  .sec-tit{font-size:clamp(22px,5.5vw,38px);}\n\n  /* GRIDS */\n  .sk-grid{grid-template-columns:1fr;}\n  .ct-grid{grid-template-columns:1fr;gap:8px;}\n  .f2{grid-template-columns:1fr;}\n\n  /* TOUCH-FRIENDLY CARDS */\n  .card{touch-action:pan-y;}\n\n  /* FOOTER */\n  .ft-main{padding:28px 24px 20px;}\n  .ft-bottom{padding:12px 24px;}\n  .ebar{padding:0 20px;}\n}\n\n/* \u2500\u2500 PHONE (\u2264480px) \u2500\u2500 */\n@media(max-width:480px){\n  /* NAV */\n  nav{padding:0 14px;height:52px;}\n  .nav-brand{font-size:13px;}\n  .nav-drawer{top:52px;padding:10px 14px 16px;}\n  .nav-drawer a{font-size:12px;padding:10px 12px;}\n\n  /* HERO NAME */\n  .nl1,.nl2{font-size:6.5vw;}\n  .nl3{font-size:11px;letter-spacing:.03em;}\n  .h-info{padding:64px 14px 28px;}\n  .h-badge{font-size:10px;padding:5px 12px;}\n  .h-role{font-size:12px;gap:8px;}\n  .h-about{padding:14px 16px;}\n  .ab-tx{font-size:13px;line-height:1.7;}\n  .h-links{gap:6px;}\n  .hl{font-size:10px;padding:6px 12px;}\n  .h-gallery{padding:20px 14px 32px;}\n  .h-gallery-inner{max-width:100%;}\n\n  /* STATS */\n  .st-n{font-size:20px;}\n  .st{padding:10px 6px;}\n  .st-l{font-size:9px;}\n\n  /* GALLERY */\n  .gbar{padding:10px 12px;}\n  .gfoot{padding:10px 12px;}\n  .gcounter{font-size:26px;}\n\n  /* SECTIONS */\n  .sec{padding:44px 14px;}\n  .sec-tit{font-size:clamp(20px,7vw,32px);}\n  .sec-ctrl{gap:6px;}\n  .swb{width:32px;height:32px;font-size:15px;}\n  .swpg{font-size:10px;}\n  .dh{display:none;}\n\n  /* CARDS */\n  .ci{padding:16px;}\n  .ai{padding:16px;gap:12px;}\n  .cnum,.ai-n{font-size:32px;}\n  .ctit,.ai-tit{font-size:14px;}\n  .cdesc,.ai-desc{font-size:12px;line-height:1.6;}\n  .ctag{font-size:9px;padding:3px 8px;}\n\n  /* CONTACT FORM */\n  .dm-hd,.dm-body{padding:16px;}\n  .dm-row{grid-template-columns:1fr;}\n  .dm-footer{flex-direction:column;align-items:flex-start;}\n  .dm-btn{width:100%;justify-content:center;}\n\n  /* MODAL */\n  .mbox{padding:24px 16px;}\n  .m-title{font-size:20px;}\n\n  /* EDIT BAR */\n  .ebar{height:44px;padding:0 14px;}\n  .ebar-lbl{font-size:10px;}\n  .btn-save{padding:6px 14px;font-size:10px;}\n\n  /* EDIT PANELS */\n  .edp{padding:16px;}\n  .ei{padding:12px;}\n  .fg input,.fg textarea{font-size:12px;padding:8px 10px;}\n\n  /* FOOTER */\n  .ft-main{padding:22px 14px 16px;}\n  .ft-bottom{padding:10px 14px;}\n  .ft-trevelade{font-size:14px;}\n  .ft-copy{font-size:8px;}\n\n  /* BACK TO TOP \u2014 handled in base CSS */\n}\n\n/* \u2500\u2500 VERY SMALL (\u2264360px) \u2500\u2500 */\n@media(max-width:360px){\n  .nl1,.nl2{font-size:7vw;}\n  .h-info{padding:58px 12px 24px;}\n  .sec{padding:36px 12px;}\n  nav{padding:0 12px;}\n  .ebar{padding:0 12px;}\n  .hed-wrap{padding:0 12px;}\n  .ft-main{padding:18px 12px 14px;}\n  .ft-bottom{padding:10px 12px;}\n}\n\n\n";
