async function exportHTML(){
  if(typeof JSZip==='undefined'){alert('JSZip not loaded — wait a moment.');return;}
  const toast=document.createElement('div');
  toast.style.cssText='position:fixed;bottom:32px;left:50%;transform:translateX(-50%);background:var(--a1);color:#fff;font-family:var(--fc);font-size:12px;letter-spacing:.08em;padding:12px 28px;border-radius:40px;z-index:99999;font-weight:600;transition:opacity .4s;';
  toast.textContent='⏳ Building zip...';
  document.body.appendChild(toast);
  try{
    save();
    const h=snap();
    const state={ph:PH,edu:D.edu,cert:D.cert,sk:D.sk,proj:D.proj,ach:D.ach,sem:D.sem,exp:D.exp,ct:D.ct,formulas:window.FORMULAS||[]};
    const bakedData=_JS_DTPL
      .replace('let PH=[],PI=0;','let PH='+JSON.stringify(state.ph)+',PI=0;')
      .replace(/const D=\{[\s\S]*?\};/,'const D='+JSON.stringify({edu:state.edu,cert:state.cert,sk:state.sk,proj:state.proj,ach:state.ach,sem:state.sem,exp:state.exp,ct:state.ct})+';');
    const heroInit='<script>(function(){'
      +'function sv(id,v){var e=document.getElementById(id);if(e&&v!==undefined)e.textContent=v;}'
      +'document.addEventListener("DOMContentLoaded",function(){'
      +'sv("hFirst",'+JSON.stringify(h.fn)+');sv("hMid",'+JSON.stringify(h.mn)+');sv("hLast",'+JSON.stringify(h.ln)+');'
      +'sv("hBadge",'+JSON.stringify(h.bd)+');sv("hChip",'+JSON.stringify(h.cp)+');sv("hSpec",'+JSON.stringify(h.sp)+');'
      +'sv("hAbout",'+JSON.stringify(h.ab)+');'
      +'sv("sP",'+JSON.stringify(h.s1)+');sv("sA",'+JSON.stringify(h.s2)+');'
      +'sv("sY",'+JSON.stringify(h.s3)+');sv("sL",'+JSON.stringify(h.s4)+');'
      +'var g=document.getElementById;'
      +'if(g("lgh"))g("lgh").href='+JSON.stringify(h.gh||'')+';'
      +'if(g("lweb"))g("lweb").href='+JSON.stringify(h.web||'')+';'
      +'if(g("lem"))g("lem").href="mailto:"+'+JSON.stringify(h.em||'')+';'
      +'});})();<\/script>';
    const title=document.title||'Johndaleverth Pastorfide Echanova — CpE Portfolio';
    const indexHtml='<!DOCTYPE html>\n<html lang="en">\n<head>\n'
      +'  <meta charset="UTF-8"/>\n'
      +'  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>\n'
      +'  <title>'+title+'<\/title>\n'
      +'  <link rel="preconnect" href="https://fonts.googleapis.com"/>\n'
      +'  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin/>\n'
      +'  <link href="https://fonts.googleapis.com/css2?family=Syne:wght@400;500;600;700;800&family=Inter:wght@300;400;500&family=JetBrains+Mono:wght@300;400;500&display=swap" rel="stylesheet"/>\n'
      +'  <link rel="stylesheet" href="css/style.css"/>\n'
      +'<\/head>\n<body>\n'
      +_BODY+'\n'
      +heroInit+'\n'
      +'  <script src="js\/data.js"><\/script>\n'
      +'  <script src="js\/security.js"><\/script>\n'
      +'  <script src="js\/auth.js"><\/script>\n'
      +'  <script src="js\/storage.js"><\/script>\n'
      +'  <script src="js\/swiper.js"><\/script>\n'
      +'  <script src="js\/render.js"><\/script>\n'
      +'  <script src="js\/main.js"><\/script>\n'
      +'  <script src="js\/scroll.js"><\/script>\n'
      +'  <script src="js\/splash.js"><\/script>\n'
      +'  <script src="js\/counters.js"><\/script>\n'
      +'<\/body>\n<\/html>';
    const zip=new JSZip();
    const cf=zip.folder('css'),jf=zip.folder('js');
    zip.file('index.html',indexHtml);
    zip.file('README.md','# Trevelade Portfolio\nExported: '+new Date().toLocaleString()+'\n\nDeploy folder to GitHub Pages or Netlify.\nOpen with VS Code Live Server for local preview.');
    cf.file('style.css',"@import url('base.css');\n@import url('hero.css');\n@import url('sections.css');\n@import url('ui.css');\n@import url('responsive.css');\n");
    cf.file('base.css',_CSS_BASE);cf.file('hero.css',_CSS_HERO);
    cf.file('sections.css',_CSS_SEC);cf.file('ui.css',_CSS_UI);cf.file('responsive.css',_CSS_RES);
    jf.file('data.js',bakedData);
    jf.file('security.js',_JS_SEC);jf.file('auth.js',_JS_AUTH);
    jf.file('storage.js',_JS_STOR);
    jf.file('swiper.js',_JS_SWP);jf.file('render.js',_JS_REN);jf.file('main.js',_JS_MAIN);
    jf.file('scroll.js',_JS_SCR);jf.file('splash.js',_JS_SPL);jf.file('counters.js',_JS_CNT);
    const blob=await zip.generateAsync({type:'blob',compression:'DEFLATE',compressionOptions:{level:6}});
    const a=document.createElement('a');
    a.href=URL.createObjectURL(blob);a.download='trevelade-portfolio-export.zip';
    document.body.appendChild(a);a.click();
    setTimeout(()=>{URL.revokeObjectURL(a.href);a.remove();},1000);
    toast.textContent='✓ Zip downloaded!';
    toast.style.background='var(--a5)';toast.style.color='#000';
    setTimeout(()=>{toast.style.opacity='0';setTimeout(()=>toast.remove(),400);},4000);
  }catch(err){
    toast.textContent='✗ Export failed: '+err.message;
    toast.style.background='#ff4444';
    setTimeout(()=>toast.remove(),4000);
    console.error('exportHTML:',err);
  }
}
function loadS(){
  try{
    var raw=localStorage.getItem('jpe_v9');if(!raw)return;
    var d=JSON.parse(raw);
    if(d.h){var h=d.h,s=function(id,v){var e=$(id);if(e&&v!==undefined)e.textContent=v;};
      s('hFirst',h.fn);s('hMid',h.mn);s('hLast',h.ln);
      s('hBadge',h.bd);s('hChip',h.cp);s('hSpec',h.sp);s('hAbout',h.ab);
      s('sP',h.s1);s('sA',h.s2);s('sY',h.s3);s('sL',h.s4);
      if($('lgh')&&h.gh)$('lgh').href=h.gh;
      if($('lweb')&&h.web)$('lweb').href=h.web;
      if($('lem')&&h.em)$('lem').href='mailto:'+h.em;}
    if(d.ph)PH=d.ph;
    if(d.edu)D.edu=d.edu;if(d.cert)D.cert=d.cert;if(d.sk)D.sk=d.sk;
    if(d.proj)D.proj=d.proj;if(d.ach)D.ach=d.ach;if(d.sem)D.sem=d.sem;
    if(d.exp)D.exp=d.exp;if(d.ct)D.ct=d.ct;
    if(d.formulas&&d.formulas.length)window.FORMULAS=d.formulas;
  }catch(e){}
}
